select * from
`t_secret`


		secret_key = #{secretKey}


		and status = #{status}


order by id limit 1

select count(1) from
`t_secret`


		secret_key = #{secretKey}


		and status = #{status}

SELECT t.*,p.`package_name` AS packageName FROM 
(
		SELECT t.`id` AS id,t.`secret_key` AS secretKey,t.`order_id` AS orderId,t.`status` AS STATUS,
		t.`create_date` AS createDate ,t.`update_date` AS updateDate,
		o.`mobile`,o.`package_id` AS packageId
		FROM `t_secret` t LEFT JOIN `order` o ON t.`order_id`=o.`id`


					t.secret_key = #{entity.secretKey}


					and t.status = #{entity.status}



					and t.create_date >= #{entity.beginDate} and  t.create_date <= #{entity.endDate} 



		ORDER by id desc limit ${page.begin},${page.limit} 

	) t LEFT JOIN `pic_package` p ON t.packageId = p.`package_id`

SELECT count(1) FROM `t_secret` t


			t.secret_key = #{entity.secretKey}


			and t.status = #{entity.status}



			and t.create_date >= #{entity.beginDate} and  t.create_date <= #{entity.endDate}
